import * as path from "path";
import * as util from "util";
import * as context from "./context";
import * as vers from "./version";
import * as core from "@actions/core";
import * as tc from "@actions/tool-cache";
export async function install(version) {
    const validVersion = await vers.getVersion(version);
    if (!validVersion) {
        throw new Error(`Cannot find Changie '${version}' release`);
    }
    const binName = context.osPlat == "win32" ? "changie.exe" : "changie";
    const cachedPath = tc.find("changie-action", validVersion);
    if (cachedPath) {
        core.info(`Found Changie ${validVersion} in tool cache`);
        return path.join(cachedPath, binName);
    }
    const filename = getFilename(validVersion);
    const downloadUrl = util.format("https://github.com/miniscruff/changie/releases/download/%s/%s", validVersion, filename);
    core.info(`Downloading ${downloadUrl}`);
    const downloadPath = await tc.downloadTool(downloadUrl);
    core.debug(`Downloaded to ${downloadPath}`);
    core.info("Extracting Changie");
    let extPath;
    if (context.osPlat == "win32") {
        extPath = await tc.extractZip(downloadPath);
    }
    else {
        extPath = await tc.extractTar(downloadPath);
    }
    core.debug(`Extracted to ${extPath}`);
    const cachePath = await tc.cacheDir(extPath, "changie-action", validVersion);
    core.debug(`Cached to ${cachePath}`);
    const exePath = path.join(cachePath, binName);
    core.debug(`Exe path is ${exePath}`);
    return exePath;
}
const getFilename = (version) => {
    let arch;
    switch (context.osArch) {
        case "x64": {
            arch = "amd64";
            break;
        }
        case "x32": {
            arch = "386";
            break;
        }
        case "arm": {
            arch = "arm64";
            break;
        }
        default: {
            arch = context.osArch;
            break;
        }
    }
    const platform = context.osPlat == "win32"
        ? "windows"
        : context.osPlat == "darwin"
            ? "darwin"
            : "linux";
    const ext = context.osPlat == "win32" ? "zip" : "tar.gz";
    core.debug(`osArch: ${context.osArch}`);
    core.debug(`osPlat: ${context.osPlat}`);
    core.debug(`version: ${version}`);
    core.debug(`arch: ${arch}`);
    core.debug(`platform: ${platform}`);
    core.debug(`ext: ${ext}`);
    const filename = `changie_${version.substr(1)}_${platform}_${arch}.${ext}`;
    core.info(`filename: ${filename}`);
    return filename;
};
