import * as httpm from '@actions/http-client';
export const getVersion = async (version) => {
    if (version.toLowerCase() !== "latest") {
        return version;
    }
    const http = new httpm.HttpClient('changie-action');
    const url = 'https://changie.dev/version.json';
    const getVersion = http.getJson(url);
    return getVersion.then(response => {
        if (response.result == null) {
            return undefined;
        }
        return response.result.latest;
    });
};
